type ReturnType<T extends (...args: any) => any> = T extends (...args: any) => infer R ? R : any;

// Basic usage
function fetchUser(id: string): Promise<User> { /* ... */ }

type FetchResult = ReturnType<typeof fetchUser>;  // Promise<User>
type User        = Awaited<ReturnType<typeof fetchUser>>; // User — unwrap the promise

// Inline function types work too
type Add = (a: number, b: number) => number;
type AddResult = ReturnType<Add>; // number

// Works with generic functions — resolves to the widest form
function identity<T>(x: T): T { return x; }
type IdentityResult = ReturnType<typeof identity>; // unknown (T not yet bound)

// Implementation
type Parameters<T extends (...args: any) => any> = T extends (...args: infer P) => any ? P : never;

