class UserService {
  constructor(private http: HttpClient, private config: AppConfig) {}
  getUser(id: string): Observable<User> { return this.http.get<User>(`/users/${id}`); }
}

type ServiceCtorArgs = ConstructorParameters<typeof UserService>;
// [http: HttpClient, config: AppConfig]

type ServiceInstance = InstanceType<typeof UserService>;
// UserService

// Generic factory pattern — works with any class
function createService<T extends new (...args: any[]) => any>(
  Ctor: T,
  ...args: ConstructorParameters<T>
): InstanceType<T> {
  return new Ctor(...args);
}

const svc = createService(UserService, httpClient, appConfig); // InstanceType<typeof UserService>

@Injectable({ providedIn: 'root' })
export class ProductService {
