// canActivate may return bool | UrlTree | Observable<bool | UrlTree> | Promise<bool | UrlTree>
function authGuard(route: ActivatedRouteSnapshot, state: RouterStateSnapshot) {
  return inject(AuthService).isAuthenticated().pipe(
    map(ok => ok || router.createUrlTree(['/login']))
  );
}

