// A memoize helper that preserves the wrapped function's type
function memoize<F extends (...args: any[]) => any>(fn: F):
  (...args: Parameters<F>) => ReturnType<F> {
  const cache = new Map<string, ReturnType<F>>();
  return (...args: Parameters<F>): ReturnType<F> => {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key)!;
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

// Usage — the returned function has the same signature as the original
function expensiveCalc(x: number, y: number): number { return x ** y; }
const memoedCalc = memoize(expensiveCalc);
// memoedCalc: (x: number, y: number) => number — derived, not declared

