interface ApiClient {
  getUser(id: string): Promise<User>;
  listProducts(category: string): Promise<Product[]>;
  createOrder(payload: NewOrder): Promise<Order>;
}

// Derive a type that holds the resolved result of every API method
type ApiResults = {
  [K in keyof ApiClient]: Awaited<ReturnType<ApiClient[K]>>;
};
// {
//   getUser: User;
//   listProducts: Product[];
//   createOrder: Order;
// }

// Cache keyed by method — guarantees each cache slot matches its method's return
class ResultCache {
  #store: Partial<ApiResults> = {};
  set<K extends keyof ApiResults>(key: K, value: ApiResults[K]): void {
    this.#store[key] = value;
  }
  get<K extends keyof ApiResults>(key: K): ApiResults[K] | undefined {
    return this.#store[key];
  }
}

// Partial application — fix the first N args, leave the rest open
type DropFirst<T extends unknown[]> = T extends [unknown, ...infer Rest] ? Rest : never;

function partial<F extends (...args: any[]) => any>(
  fn: F,
  first: Parameters<F>[0]
): (...rest: DropFirst<Parameters<F>>) => ReturnType<F> {
  return (...rest) => fn(first, ...rest);
}

// Usage: fix the userId, leave filters open
