const userSearch = partial(searchOrders, 'user-123');
// Type: (filters: OrderFilters, page: number) => Order[]
const results = userSearch({ status: 'pending' }, 1); // type-safe call

import { SimpleChanges } from '@angular/core';

// A base class that wraps ngOnChanges for reactive handling
abstract class ReactiveComponent {
  abstract ngOnChanges(changes: SimpleChanges): void;

  protected changesOf<K extends keyof SimpleChanges>(
    changes: Parameters<this['ngOnChanges']>[0],
    key: K
  ) {
    return changes[key as string];
  }
}

// In tests — derive what ngOnChanges expects without re-declaring SimpleChanges
type OnChangesArgs = Parameters<InstanceType<typeof MyComponent>['ngOnChanges']>;
// [changes: SimpleChanges]

function buildChanges(overrides: SimpleChanges = {}): OnChangesArgs[0] {
  return { ...overrides };
}

// Handler function defines the contract
function handleUserCreated(id: string, role: 'admin' | 'user', timestamp: Date): void { /* ... */ }

