type UserCreatedPayload = Parameters<typeof handleUserCreated>;
// [id: string, role: 'admin' | 'user', timestamp: Date]

@Component({ /* ... */ })
export class UserFormComponent {
  // EventEmitter type matches handler
  @Output() userCreated = new EventEmitter<UserCreatedPayload>();

  submit(form: NgForm): void {
    this.userCreated.emit(['u-123', 'user', new Date()]);
    //                    ^ TypeScript ensures this tuple matches the handler args
  }
}
